/**
 * importTop500.js
 * ─────────────────────────────────────────────────────────────────────────────
 * Imports 500 hand-curated, professionally verified AI tools into MongoDB.
 * Covers: Most-used, trending, editor's choice, newly launched, and
 * professional-grade tools across all major AI categories.
 *
 * Curation criteria:
 *  - Used by professionals / enterprises in their respective field
 *  - Trending on Product Hunt, Twitter/X, Reddit, HN in 2024-2025
 *  - Editor's choice: uniquely capable, category-defining tools
 *  - Recently launched with strong traction
 *
 * Run:       node scripts/importTop500.js
 * Dry run:   node scripts/importTop500.js --dry-run
 * ─────────────────────────────────────────────────────────────────────────────
 */

import mongoose from 'mongoose'
import dotenv from 'dotenv'
import path from 'path'
import { fileURLToPath } from 'url'
import slugify from 'slugify'

const __filename = fileURLToPath(import.meta.url)
const __dirname = path.dirname(__filename)
dotenv.config({ path: path.join(__dirname, '../.env') })

const DRY_RUN = process.argv.includes('--dry-run')

async function connectDB() {
  await mongoose.connect(process.env.MONGODB_URI)
  console.log('✅ MongoDB Connected\n')
}

async function ensureCategories(categoryNames) {
  const col = mongoose.connection.collection('categories')
  const map = {}
  const existing = await col.find({}).toArray()
  for (const cat of existing) { map[cat.name] = cat._id; map[cat.slug] = cat._id }
  for (const name of categoryNames) {
    if (!map[name]) {
      const slug = slugify(name, { lower: true, strict: true })
      if (!map[slug]) {
        const res = await col.insertOne({ name, slug, description: `Discover the best ${name} AI tools`, icon: '🤖', isActive: true, order: 99, toolCount: 0, createdAt: new Date(), updatedAt: new Date() })
        map[name] = res.insertedId; map[slug] = res.insertedId
        console.log(`   📁 Created category: ${name}`)
      } else { map[name] = map[slug] }
    }
  }
  return map
}

